1	import { apiClient } from "@/services/api";
2	
3	export interface DashboardSummary {
4	  id: number;
5	  name: string;
6	  description: string | null;
7	  widget_count: number;
8	  allowed_store_ids: number[];
9	  created_at: string;
10	  updated_at: string;
11	}
12	
13	export interface DashboardWidget {
14	  id: string;
15	  kind: "kpi" | "trend" | "breakdown" | "table";
16	  title: string;
17	  metric: "revenue" | "orders" | "refunds" | "gross_margin";
18	  dimension: "store" | "date" | null;
19	  x: number;
20	  y: number;
21	  w: number;
22	  h: number;
23	  filters?: Array<{
24	    key: string;
25	    operator: "eq" | "in" | "gte" | "lte" | "between";
26	    value: string;
27	  }>;
28	  links?: Array<{
29	    source_filter_key: string;
30	    target_filter_key: string;
31	  }>;
32	}
33	
34	export interface DashboardData {
35	  filters: { store_ids: number[]; start_date: string; end_date: string };
36	  totals: {
37	    orders: number;
38	    revenue: string;
39	    refunds: string;
40	    cost: string;
41	    gross_margin: string;
42	  };
43	  by_store?: Array<{
44	    store_id: number;
45	    store_name: string;
46	    orders: number;
47	    revenue: string;
48	    refunds: string;
49	    cost: string;
50	    gross_margin: string;
51	  }>;
52	  by_date?: Array<{
53	    business_date: string;
54	    orders: number;
55	    revenue: string;
56	    refunds: string;
57	    cost: string;
58	    gross_margin: string;
59	  }>;
60	  rows?: Array<{
61	    store_id: number;
62	    store_name: string;
63	    business_date: string;
64	    orders: number;
65	    revenue: string;
66	    refunds: string;
67	    cost: string;
68	    gross_margin: string;
69	  }>;
70	}
71	
72	export interface DashboardDetail {
73	  id: number;
74	  name: string;
75	  description: string | null;
76	  widgets: DashboardWidget[];
77	  allowed_store_ids: number[];
78	  default_start_date: string | null;
79	  default_end_date: string | null;
80	  store_options: Array<{ id: number; name: string }>;
81	  read_only: boolean;
82	  data: DashboardData;
83	}
84	
85	export interface SharedDashboardDetail {
86	  dashboard_id: number;
87	  token: string;
88	  name: string;
89	  description: string | null;
90	  widgets: DashboardWidget[];
91	  allowed_store_ids: number[];
92	  store_options: Array<{ id: number; name: string }>;
93	  read_only: boolean;
94	  data: DashboardData;
95	  created_at: string;
96	  updated_at: string;
97	}
98	
99	export interface StoreDrillDown {
100	  dashboard_id: number;
101	  store_id: number;
102	  store_name: string;
103	  start_date: string;
104	  end_date: string;
105	  orders: number;
106	  revenue: string;
107	  refunds: string;
108	  cost: string;
109	  gross_margin: string;
110	}
111	
112	export interface DateDrillDown {
113	  dashboard_id: number;
114	  business_date: string;
115	  start_date: string;
116	  end_date: string;
117	  orders: number;
118	  revenue: string;
119	  refunds: string;
120	  cost: string;
121	  gross_margin: string;
122	}
123	
124	export async function listDashboards() {
125	  const { data } = await apiClient.get<DashboardSummary[]>("/analytics/dashboards");
126	  return data;
127	}
128	
129	export async function createDashboard(payload: {
130	  name: string;
131	  description?: string;
132	  widgets: DashboardWidget[];
133	  allowed_store_ids: number[];
134	  default_start_date?: string;
135	  default_end_date?: string;
136	}) {
137	  const { data } = await apiClient.post<DashboardDetail>("/analytics/dashboards", payload);
138	  return data;
139	}
140	
141	export async function getDashboard(dashboardId: number) {
142	  const { data } = await apiClient.get<DashboardDetail>(`/analytics/dashboards/${dashboardId}`);
143	  return data;
144	}
145	
146	export async function getSharedDashboard(token: string) {
147	  const { data } = await apiClient.get<SharedDashboardDetail>(`/analytics/shared/${token}`);
148	  return data;
149	}
150	
151	export async function exportDashboardMetadata(dashboardId: number, format: "csv" | "png" | "pdf") {
152	  const { data } = await apiClient.get<{
153	    filename: string;
154	    content_type: string;
155	    size_bytes: number;
156	  }>(`/analytics/dashboards/${dashboardId}/export/metadata`, { params: { format } });
157	  return data;
158	}
159	
160	function _filenameFromDisposition(
161	  contentDisposition: string | undefined,
162	  fallback: string,
163	): string {
164	  if (!contentDisposition) {
165	    return fallback;
166	  }
167	  const match = contentDisposition.match(/filename="?([^";]+)"?/i);
168	  return match?.[1] ?? fallback;
169	}
170	
171	export async function exportDashboardFile(dashboardId: number, format: "csv" | "png" | "pdf") {
172	  const response = await apiClient.get<Blob>(`/analytics/dashboards/${dashboardId}/export`, {
173	    params: { format },
174	    responseType: "blob",
175	  });
176	  const fallbackName = `dashboard-${dashboardId}.${format}`;
177	  const filename = _filenameFromDisposition(response.headers["content-disposition"], fallbackName);
178	  return {
179	    blob: response.data,
180	    filename,
181	  };
182	}
183	
184	export async function getDashboardStoreDrilldown(dashboardId: number, storeId: number) {
185	  const { data } = await apiClient.get<StoreDrillDown>(
186	    `/analytics/dashboards/${dashboardId}/drilldown/store/${storeId}`,
187	  );
188	  return data;
189	}
190	
191	export async function getDashboardDateDrilldown(dashboardId: number, businessDate: string) {
192	  const { data } = await apiClient.get<DateDrillDown>(
193	    `/analytics/dashboards/${dashboardId}/drilldown/date/${businessDate}`,
194	  );
195	  return data;
196	}
197	
198	export async function createDashboardShareLink(
199	  dashboardId: number,
200	  payload: { start_date?: string; end_date?: string; allowed_store_ids?: number[] } = {},
201	) {
202	  const { data } = await apiClient.post(
203	    `/analytics/dashboards/${dashboardId}/share-links`,
204	    payload,
205	  );
206	  return data as {
207	    id: number;
208	    dashboard_id: number;
209	    token: string;
210	    share_url: string;
211	    readonly: boolean;
212	    is_active: boolean;
213	  };
214	}
