1	<template>
2	  <section>
3	    <h1>Analytics Dashboards</h1>
4	    <p>
5	      View dashboard summaries, drill into details, verify exports, and generate read-only links.
6	    </p>
7	
8	    <section class="panel">
9	      <h2>Dashboards</h2>
10	      <button class="btn" @click="refreshDashboards">Refresh</button>
11	      <table class="data-table" v-if="dashboards.length > 0">
12	        <thead>
13	          <tr>
14	            <th>ID</th>
15	            <th>Name</th>
16	            <th>Widgets</th>
17	            <th>Stores</th>
18	            <th>Action</th>
19	          </tr>
20	        </thead>
21	        <tbody>
22	          <tr v-for="row in dashboards" :key="row.id">
23	            <td>{{ row.id }}</td>
24	            <td>{{ row.name }}</td>
25	            <td>{{ row.widget_count }}</td>
26	            <td>{{ row.allowed_store_ids.join(", ") }}</td>
27	            <td><button class="btn btn-small" @click="onSelectDashboard(row.id)">Open</button></td>
28	          </tr>
29	        </tbody>
30	      </table>
31	    </section>
32	
33	    <section class="panel" v-if="selectedDashboard">
34	      <h2>Dashboard Detail: {{ selectedDashboard.name }}</h2>
35	      <p>
36	        Orders: {{ selectedDashboard.data.totals.orders }} | Revenue:
37	        {{ selectedDashboard.data.totals.revenue }} | Gross Margin:
38	        {{ selectedDashboard.data.totals.gross_margin }}
39	      </p>
40	      <div class="inline-actions">
41	        <button class="btn btn-small" @click="onExportMeta('csv')">CSV Meta</button>
42	        <button class="btn btn-small" @click="onExportMeta('png')">PNG Meta</button>
43	        <button class="btn btn-small" @click="onExportMeta('pdf')">PDF Meta</button>
44	        <button class="btn btn-small" @click="onExportFile('csv')">Export CSV</button>
45	        <button class="btn btn-small" @click="onExportFile('png')">Export PNG</button>
46	        <button class="btn btn-small" @click="onExportFile('pdf')">Export PDF</button>
47	        <button class="btn btn-small" @click="onCreateShare">Create Share Link</button>
48	      </div>
49	      <div class="form-grid" style="margin-top: 12px">
50	        <select v-model.number="selectedStoreIdForDrill">
51	          <option :value="0">Select store for drilldown</option>
52	          <option v-for="row in selectedDashboard.data.by_store ?? []" :key="`drill-store-${row.store_id}`" :value="row.store_id">
53	            {{ row.store_name }} ({{ row.store_id }})
54	          </option>
55	        </select>
56	        <input v-model="selectedDateForDrill" type="date" />
57	        <button class="btn btn-small" @click="onStoreDrilldown">Drill by Store</button>
58	        <button class="btn btn-small" @click="onDateDrilldown">Drill by Date</button>
59	      </div>
60	      <p v-if="exportMeta">
61	        Export: {{ exportMeta.filename }} ({{ exportMeta.content_type }},
62	        {{ exportMeta.size_bytes }} bytes)
63	      </p>
64	      <p v-if="lastDownloadedFileName">Downloaded: {{ lastDownloadedFileName }}</p>
65	      <p v-if="shareLink">Share URL: {{ shareLink }}</p>
66	
67	      <section class="panel" v-if="storeDrilldown">
68	        <h3>Store Drilldown</h3>
69	        <p>
70	          {{ storeDrilldown.store_name }} ({{ storeDrilldown.store_id }}) | Orders: {{ storeDrilldown.orders }} | Revenue:
71	          {{ storeDrilldown.revenue }} | Margin: {{ storeDrilldown.gross_margin }}
72	        </p>
73	      </section>
74	
75	      <section class="panel" v-if="dateDrilldown">
76	        <h3>Date Drilldown</h3>
77	        <p>
78	          {{ dateDrilldown.business_date }} | Orders: {{ dateDrilldown.orders }} | Revenue: {{ dateDrilldown.revenue }} |
79	          Margin: {{ dateDrilldown.gross_margin }}
80	        </p>
81	      </section>
82	    </section>
83	
84	    <p v-if="errorMessage" class="error">{{ errorMessage }}</p>
85	  </section>
86	</template>
87	
88	<script setup lang="ts">
89	import { onMounted, ref } from "vue";
90	
91	import {
92	  createDashboardShareLink,
93	  exportDashboardFile,
94	  exportDashboardMetadata,
95	  getDashboardDateDrilldown,
96	  getDashboard,
97	  getDashboardStoreDrilldown,
98	  listDashboards,
99	  type DateDrillDown,
100	  type DashboardDetail,
101	  type DashboardSummary,
102	  type StoreDrillDown,
103	} from "@/services/analytics";
104	import { useUiStore } from "@/stores/ui";
105	import { notifyError } from "@/utils/feedback";
106	
107	const ui = useUiStore();
108	
109	const dashboards = ref<DashboardSummary[]>([]);
110	const selectedDashboard = ref<DashboardDetail | null>(null);
111	const exportMeta = ref<{ filename: string; content_type: string; size_bytes: number } | null>(null);
112	const shareLink = ref("");
113	const lastDownloadedFileName = ref("");
114	const selectedStoreIdForDrill = ref(0);
115	const selectedDateForDrill = ref("");
116	const storeDrilldown = ref<StoreDrillDown | null>(null);
117	const dateDrilldown = ref<DateDrillDown | null>(null);
118	const errorMessage = ref("");
119	
120	async function refreshDashboards() {
121	  dashboards.value = await listDashboards();
122	}
123	
124	async function onSelectDashboard(dashboardId: number) {
125	  try {
126	    errorMessage.value = "";
127	    selectedDashboard.value = await getDashboard(dashboardId);
128	    exportMeta.value = null;
129	    shareLink.value = "";
130	    lastDownloadedFileName.value = "";
131	    selectedStoreIdForDrill.value = 0;
132	    selectedDateForDrill.value = selectedDashboard.value.data.filters.start_date;
133	    storeDrilldown.value = null;
134	    dateDrilldown.value = null;
135	    ui.info("Loaded", `Dashboard ${dashboardId} loaded.`);
136	  } catch (error) {
137	    errorMessage.value = notifyError(error, "Failed to load dashboard details.");
138	  }
139	}
140	
141	function _downloadBlob(blob: Blob, filename: string) {
142	  const blobUrl = window.URL.createObjectURL(blob);
143	  const link = document.createElement("a");
144	  link.href = blobUrl;
145	  link.download = filename;
146	  document.body.appendChild(link);
147	  link.click();
148	  document.body.removeChild(link);
149	  window.URL.revokeObjectURL(blobUrl);
150	}
151	
152	async function onExportFile(format: "csv" | "png" | "pdf") {
153	  if (!selectedDashboard.value) return;
154	  try {
155	    errorMessage.value = "";
156	    const payload = await exportDashboardFile(selectedDashboard.value.id, format);
157	    _downloadBlob(payload.blob, payload.filename);
158	    lastDownloadedFileName.value = payload.filename;
159	    ui.success("Downloaded", `${format.toUpperCase()} export downloaded.`);
160	  } catch (error) {
161	    errorMessage.value = notifyError(error, "Failed to export dashboard file.");
162	  }
163	}
164	
165	async function onExportMeta(format: "csv" | "png" | "pdf") {
166	  if (!selectedDashboard.value) return;
167	  try {
168	    errorMessage.value = "";
169	    exportMeta.value = await exportDashboardMetadata(selectedDashboard.value.id, format);
170	    ui.success("Posted", `${format.toUpperCase()} export metadata generated.`);
171	  } catch (error) {
172	    errorMessage.value = notifyError(error, "Failed to load export metadata.");
173	  }
174	}
175	
176	async function onStoreDrilldown() {
177	  if (!selectedDashboard.value || !selectedStoreIdForDrill.value) return;
178	  try {
179	    errorMessage.value = "";
180	    storeDrilldown.value = await getDashboardStoreDrilldown(selectedDashboard.value.id, selectedStoreIdForDrill.value);
181	    ui.info("Loaded", `Store drilldown ready for ${storeDrilldown.value.store_name}.`);
182	  } catch (error) {
183	    errorMessage.value = notifyError(error, "Failed to load store drilldown.");
184	  }
185	}
186	
187	async function onDateDrilldown() {
188	  if (!selectedDashboard.value || !selectedDateForDrill.value) return;
189	  try {
190	    errorMessage.value = "";
191	    dateDrilldown.value = await getDashboardDateDrilldown(selectedDashboard.value.id, selectedDateForDrill.value);
192	    ui.info("Loaded", `Date drilldown ready for ${dateDrilldown.value.business_date}.`);
193	  } catch (error) {
194	    errorMessage.value = notifyError(error, "Failed to load date drilldown.");
195	  }
196	}
197	
198	async function onCreateShare() {
199	  if (!selectedDashboard.value) return;
200	  try {
201	    errorMessage.value = "";
202	    const row = await createDashboardShareLink(selectedDashboard.value.id);
203	    shareLink.value = row.share_url;
204	    ui.success("Created", "Read-only share link created.");
205	  } catch (error) {
206	    errorMessage.value = notifyError(error, "Failed to create share link.");
207	  }
208	}
209	
210	onMounted(async () => {
211	  try {
212	    await refreshDashboards();
213	  } catch {
214	    // Best-effort initial load.
215	  }
216	});
217	</script>
