12	export const useAuthStore = defineStore("auth", {
13	  state: (): AuthState => ({
14	    user: null,
15	    loading: false,
16	    initialized: false,
17	  }),
18	  getters: {
19	    isAuthenticated: (state) => Boolean(state.user),
