22	    username: (state): string => state.user?.username ?? "",
23	    displayName: (state): string => state.user?.display_name ?? "",
24	  },
25	  actions: {
26	    async initialize() {
27	      if (this.initialized) return;
28	      this.loading = true;
29	      this.user = await fetchSession();
30	      this.loading = false;
31	      this.initialized = true;
32	    },
